from azure.ai.projects import ProjectsClient
from azure.mgmt.policyinsights import PolicyInsightsClient

def policy_validated_tool_call(tool_call, credential):
    policy_client = PolicyInsightsClient(credential)

    # Check tool output against DLP policies
    compliance_check = policy_client.policy_states.list(
        policy_assignment_name='dlp-agent-tools',
        resource_id=tool_call.resource_id
    )

    if any(state.compliance_state != 'Compliant' for state in compliance_check):
        return {
            'error': 'Tool output violates enterprise DLP policy',
            'policy_violations': [state.policy_definition_reference_id for state in compliance_check]
        }

    return tool_call.execute()

# Integrate in agent middleware
middleware = {
    'type': 'policy_validation',
    'handler': policy_validated_tool_call
}

from datetime import datetime, timedelta

def fresh_grounding_filter(search_results):
    cutoff_date = datetime.now() - timedelta(days=30)
    fresh_results = []

    for result in search_results:
        # Parse publication date from Bing metadata
        pub_date = datetime.fromisoformat(result.get('date_published', '1970-01-01'))

        if pub_date > cutoff_date:
            result['freshness_score'] = (datetime.now() - pub_date).days
            fresh_results.append(result)
        else:
            print(f'Skipped stale result: {result["title"]} ({pub_date})')

    return {
        'results': fresh_results,
        'freshness_warning': len(search_results) != len(fresh_results)
    }

# Agent grounding config
agent_config = {
    'grounding': {
        'bing_search': {
            'freshness_filter': fresh_grounding_filter,
            'max_age_days': 30
        }
    }
}

class TokenAwareThreadManager:
    def __init__(self, max_tokens=128000):
        self.max_tokens = max_tokens
        self.current_tokens = 0
        self.conversation_summary = []

    def add_message(self, message):
        msg_tokens = len(message.content) // 4  # Rough token estimate

        if self.current_tokens + msg_tokens > self.max_tokens * 0.9:
            # Summarize and reset
            self.conversation_summary.append(self.summarize_thread())
            self.current_tokens = 0

        self.current_tokens += msg_tokens
        return message

    def summarize_thread(self):
        return {
            'type': 'thread_summary',
            'tokens_saved': self.current_tokens,
            'reset': True
        }

# Usage in Azure AI Agent Service
thread_manager = TokenAwareThreadManager()
for message in incoming_messages:
    processed = thread_manager.add_message(message)
    agent.process_message(processed)
